def isValid(self, s: str) -> bool:
    stack = []
    open_braces = '()[]{}'
    for char in s:
        if char in open_braces:
            stack.append(char)
        else:
            if len(stack) == 0:
                return False
            stack.pop()
    if len(stack) != 0:
        return False
    return len(s) == 0

